import{_ as a,o as i,c as n,a3 as l}from"./chunks/framework.DXXx-gl1.js";const c=JSON.parse('{"title":"Windows 24H2 及更高版本的 GPT \\"修复\\"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/InstallationGuides/GPTErrata.md","filePath":"zh/InstallationGuides/GPTErrata.md","lastUpdated":1771005114000}'),t={name:"zh/InstallationGuides/GPTErrata.md"};function e(p,s,h,r,d,k){return i(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="windows-24h2-及更高版本的-gpt-修复" tabindex="-1">Windows 24H2 及更高版本的 GPT &quot;修复&quot; <a class="header-anchor" href="#windows-24h2-及更高版本的-gpt-修复" aria-label="Permalink to &quot;Windows 24H2 及更高版本的 GPT &quot;修复&quot;&quot;">​</a></h1><p>自 24H2 以来，有一个奇怪的 bug，会在 OOBE 或更新后将您的设备变成砖头。 本指南提供一种需要在安装24H2之前、修改分区表执行的方法以帮助您防止这种情况发生。</p><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>请在每次安装/重新安装 Windows之前，或者重新分区之后进行GPT修复。</p></div><h2 id="要求" tabindex="-1">要求 <a class="header-anchor" href="#要求" aria-label="Permalink to &quot;要求&quot;">​</a></h2><ul><li>一部运行 Android 的手机</li><li>Termux、gdisk 和 Android 上的 root 访问权限。</li></ul><h2 id="android-linux-中的步骤" tabindex="-1">Android/Linux 中的步骤 <a class="header-anchor" href="#android-linux-中的步骤" aria-label="Permalink to &quot;Android/Linux 中的步骤&quot;">​</a></h2><ul><li>安装 <a href="https://github.com/termux/termux-app/releases" target="_blank" rel="noreferrer">Termux</a></li><li>gptfdisk 的一般设置和安装</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 替换镜像</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  *使用空格选择并回车确认*</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">termux-change-repo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 更新</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装 root repo</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root-repo</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装 gptfdisk</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tsu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gptfdisk</span></span></code></pre></div><ul><li>打开 gdisk 并运行</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tsu</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 当 termux 请求 root 权限时，请同意。</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdisk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/block/sda</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # sda 可以是 sda、sdb 或其他字母</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 gdisk CLI 中</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">x</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">j</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接回车，不输入任何内容</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">k</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 直接回车，不输入任何内容</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">w</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">y</span></span></code></pre></div><ul><li><strong>对 sdb、sdc、sdd、sde、sdf... 重复</strong> 最后一步，直到 gdisk 给出错误。</li></ul><h2 id="为什么-windows-会损坏您的-gpt" tabindex="-1">为什么 Windows 会损坏您的 GPT？ <a class="header-anchor" href="#为什么-windows-会损坏您的-gpt" aria-label="Permalink to &quot;为什么 Windows 会损坏您的 GPT？&quot;">​</a></h2><p>Windows 增加了除 lun0 之外所有 lun 的 <code>Starting LBA of entries</code>，但没有移动 LBA 条目并更新 CRC。 导致起始 LBA 不被识别和 GPT 损坏。然后您的设备无法再启动。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://zhuanlan.zhihu.com/p/1984041980913807755" target="_blank" rel="noreferrer">知乎 - 为什么 WOA 会破坏 GPT 并将您的设备发送到 9008</a></li><li><a href="https://t.me/project_aloha_issues/1/93859" target="_blank" rel="noreferrer">TG - 聊天消息</a></li></ul>`,15)])])}const g=a(t,[["render",e]]);export{c as __pageData,g as default};
